<div class="de">
<svg viewBox="0 0 700 360" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Zwei Lücken, die die Prüfhäufigkeit Erzeugt</text>
  <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Links: Bewertungshäufigkeit → Allokation · Rechts: geöffnete Marktstunden</text>
  <line x1="80" y1="270" x2="615" y2="270" stroke="rgba(255,255,255,.15)"/>
  <line x1="340" y1="90" x2="340" y2="270" stroke="rgba(255,255,255,.12)" stroke-dasharray="4,4"/>
